import {useRef,useState} from 'react';export default function FeedbackForm(){const[n,setN]=useState('');const[m,setM]=useState('');const msgRef=useRef();const sub=e=>{e.preventDefault();if(!n||!m){alert('Fill all fields');return;}alert('Feedback Submitted');setN('');setM('');};return <div className='card p-3'><form onSubmit={sub}><h4>Feedback</h4><input value={n} onChange={e=>setN(e.target.value)} className='form-control mt-2' placeholder='Name'/><textarea ref={msgRef} value={m} onChange={e=>setM(e.target.value)} className='form-control mt-2' placeholder='Message'></textarea><button type='button' onClick={()=>msgRef.current.focus()} className='btn btn-secondary mt-2 me-2'>Focus Message</button><button className='btn btn-success mt-2'>Submit</button></form></div>}